#!/usr/bin/env node

/**
 * Post monthly metrics summary to Slack
 */

const https = require('https');
const fs = require('fs');
const path = require('path');
const { loadMonthlyMetrics } = require('./save-metrics-to-json');
const { formatTime } = require('./shared-metrics');

const SLACK_BOT_TOKEN = process.env.SLACK_BOT_TOKEN;
const CHANNEL_NAME = 'itops-metric-reporting';

if (!SLACK_BOT_TOKEN) {
  console.error('Error: SLACK_BOT_TOKEN environment variable required');
  process.exit(1);
}

// Load metrics from cache (generated by run-monthly.sh)
let metrics;
try {
  const data = loadMonthlyMetrics();
  const current = data.currentMonth;

  // Format metrics for Slack message
  metrics = {
    period: current.period,
    resolvedCount: current.resolvedCount,
    createdCount: current.createdCount,
    overallSlaPercent: current.overallSlaPercent,
    avgTTFR: formatTime(current.avgTTFR),
    avgTTR: formatTime(current.avgTTR),
    slaBreachCount: current.slaBreachCount,
    automationPercent: current.automationPercent,
    csat: current.csat,
    workforce: current.workforce
  };
} catch (error) {
  console.error('Error loading monthly metrics from cache:', error.message);
  console.error('Make sure you run ./run-monthly.sh which generates the cache file.');
  process.exit(1);
}

// Determine status emojis based on metrics
const slaStatus = parseFloat(metrics.overallSlaPercent) >= 95 ? '✅' : '⚠️';
const csatStatus = parseFloat(metrics.csat.avgScore) >= 4.5 ? '✅' : '⚠️';
const automationStatus = parseFloat(metrics.automationPercent) >= 5 ? '✅' : '⚠️';
const backlogStatus = metrics.createdCount <= metrics.resolvedCount ? '✅' : '⚠️';

// Check if it's March (data quality warning)
const isMarch = metrics.period.toLowerCase().includes('march');

const message = `📊 *IT Ops Monthly Metrics*
📅 ${metrics.period}
${isMarch ? '\n⚠️ *Data Quality Notice:* March includes ticket clock cleanup - see analyst report for details\n' : ''}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━

🎯 *Performance*
${slaStatus} SLA: *${metrics.overallSlaPercent}%* (Target: 95%)
⏱️ TTFR: ${metrics.avgTTFR} (Target: 2h)
⏱️ TTR: ${metrics.avgTTR} (Target: 16h)
${csatStatus} CSAT: *${metrics.csat.avgScore}/5.0* (${metrics.csat.totalResponses} reviews)

📈 *Volume*
${backlogStatus} Resolved: *${metrics.resolvedCount}* tickets
📥 Created: *${metrics.createdCount}* tickets
${metrics.createdCount > metrics.resolvedCount ? '⚠️ Backlog growing' : '✅ Backlog reducing'}

🤖 *Automation*
${automationStatus} Rate: *${metrics.automationPercent}%* (Target: 5%)
⚡ Breaches: ${metrics.slaBreachCount} tickets

👥 *Workforce*
➕ Onboarded: ${metrics.workforce.fteOnboarding} FTE + ${metrics.workforce.contractorOnboarding} contractors
➖ Offboarded: ${metrics.workforce.offboarding}
📊 Net: ${metrics.workforce.netChange > 0 ? '🟢 +' : metrics.workforce.netChange < 0 ? '🔴 ' : '⚪️ '}${metrics.workforce.netChange}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━

📋 *Full Reports*
• <https://attentivemobile.atlassian.net/wiki/spaces/ISD/pages/6415089689|📊 Dashboard>
• <https://attentivemobile.atlassian.net/wiki/spaces/ISD/pages/6422003766|📈 Analyst Report>`;

function makeSlackRequest(data) {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify(data);

    const options = {
      hostname: 'slack.com',
      path: '/api/chat.postMessage',
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/json; charset=utf-8',
        'Content-Length': Buffer.byteLength(postData)
      }
    };

    const req = https.request(options, (res) => {
      let responseData = '';
      res.on('data', (chunk) => responseData += chunk);
      res.on('end', () => {
        try {
          const response = JSON.parse(responseData);
          if (response.ok) {
            resolve(response);
          } else {
            reject(new Error(`Slack API error: ${response.error}`));
          }
        } catch (e) {
          reject(new Error(`Failed to parse response: ${responseData}`));
        }
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

async function postToSlack() {
  try {
    console.log('🔄 Posting monthly metrics to Slack...');
    console.log(`Channel: #${CHANNEL_NAME}\n`);

    const response = await makeSlackRequest({
      channel: CHANNEL_NAME,
      text: message,
      unfurl_links: false,
      unfurl_media: false
    });

    console.log('✅ Monthly metrics posted to Slack successfully!');
    console.log(`Message timestamp: ${response.ts}`);

  } catch (error) {
    console.error('✗ Error posting to Slack:', error.message);
    process.exit(1);
  }
}

postToSlack();
